const body = $input.item.json.body;

console.log('=== EXTRACT AUDIO MESSAGE ID ===');
console.log('Full body:', JSON.stringify(body, null, 2));

let messageId;
let instanceName;
let remoteJid;

// Extract messageId
if (body.keyId) {
  messageId = body.keyId;
  console.log('✓ Using keyId:', messageId);
} else if (body.chatInput && body.chatInput.includes('|')) {
  const parts = body.chatInput.split('|');
  messageId = parts[1];
  console.log('✓ Extracted from chatInput:', messageId);
} else {
  throw new Error('❌ Cannot find messageId. Body: ' + JSON.stringify(body));
}

// Extract instanceName
if (body.instanceName) {
  instanceName = body.instanceName;
} else if (body.instance) {
  instanceName = body.instance;
} else {
  instanceName = 'Youlya';
  console.log('⚠️ Using default instanceName: Youlya');
}

// Extract remoteJid
remoteJid = body.remoteJid;

console.log('✅ OUTPUT:', { messageId, instanceName, remoteJid });
console.log('================================');

return [{
  json: {
    messageId: messageId,
    instanceName: instanceName,
    remoteJid: remoteJid,
    originalBody: body
  }
}];

