// === SMART PRODUCT DETECTOR v2.0: Detection Only (No Sending) ===
// SubWorkflow already sends images - this just detects if products were returned

const aiOutput = $('AI Agent').last()?.json?.output || '';

console.log('\n' + '='.repeat(70));
console.log('PRODUCT DETECTOR v2.0 - DETECTION ONLY');
console.log('='.repeat(70));
console.log('Output length:', aiOutput.length);

// Extract ALL markdown images with Shopify CDN
const shopifyPattern = /!\[([^\]]*)\]\((https:\/\/cdn\.shopify\.com\/[^)]+)\)/g;
const matches = [...aiOutput.matchAll(shopifyPattern)];

console.log('Shopify images found:', matches.length);

if (matches.length > 0) {
  console.log('\n✅ PRODUCTS DETECTED!');
  console.log(`Found ${matches.length} product images`);
  console.log('Images already sent by SubWorkflow ✅');

  // Extract just the text after products (if any)
  let textAfterProducts = aiOutput;

  // Remove all image markdown
  textAfterProducts = textAfterProducts.replace(shopifyPattern, '');

  // Remove product details blocks (السعر, المقاسات, etc.)
  textAfterProducts = textAfterProducts
    .replace(/السعر[:\s]*(?:\*{1,2})?\s*\d+\s*جنيه/gi, '')
    .replace(/الألوان[\s]*(?:المتاحة)?[:\s*]*[^\n]+/gi, '')
    .replace(/المقاسات[:\s*]*[^\n]+/gi, '')
    .replace(/الخامة[:\s*]*[^\n]+/gi, '')
    .replace(/📝[\s]*[^\n]+/gi, '')
    .replace(/---+/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  console.log('Text after products (if any):', textAfterProducts.substring(0, 100));

  console.log('='.repeat(70) + '\n');

  // Return single response indicating products were sent
  return [{
    json: {
      isProduct: true,
      productCount: matches.length,
      productsAlreadySent: true,
      // Include any text that came AFTER the products (like follow-up questions)
      followUpText: textAfterProducts || '',
      text: textAfterProducts || `تم عرض ${matches.length} منتج`
    }
  }];
}

// NO PRODUCTS - text only
console.log('\n📝 No Shopify images - Text response');
console.log('='.repeat(70) + '\n');

return [{
  json: { 
    isProduct: false,
    productsAlreadySent: false,
    isTextResponse: true,
    text: aiOutput
  }
}];
